SELECT COALESCE(value, default_value) AS config_value
FROM configuration_items
WHERE config_id = 'specific_config_id';

SELECT config_id
FROM configuration_items
WHERE group_name = 'core';

SELECT COUNT(DISTINCT config_id) 
FROM configuration_items 
WHERE status IS NOT NULL;

SELECT AVG(value) AS average_value
FROM configuration_items
WHERE data_type = 'number';

SELECT COUNT(*) AS total_active_configurations
FROM configuration_items
WHERE status = 'active';

SELECT config_id, key_name, value, data_type, flags
FROM configuration_items
WHERE group_name = 'core';

SELECT COUNT(DISTINCT created_by) AS rollback_users_count
FROM configuration_versions
WHERE is_rollback = 1;

SELECT AVG(LENGTH(comment))
FROM configuration_comments
WHERE config_id = 'your_config_id_here';

SELECT *
FROM configuration_items
WHERE status = 'active' AND created_by = 1;

SELECT *
FROM configuration_items
ORDER BY created_at DESC;
